INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1202, 189271, 3, 1682, '当往事已成灰烬', '每一个人都是独一无二的，他们各有其不同的困惑难题，也各有其不同的解决方式。作家笔下的人物、电影中的主人公也概莫能外。时间飞逝，若干年后，当我们追寻往事的时候。在时间的灰烬里（Ashs of time）能发掘出什么呢？
<br>　　　　 “很多年以后，我有一个名字叫西毒……”随着欧阳峰低缓的独语，我走进了山那边的沙漠。当我走出来的时候发现沙漠的尽头还是沙漠，天的尽头还是天。欧阳峰喜欢的女子成了他嫂子，而黄药师喜欢上朋友的妻子桃花，更因酒后的戏言使得慕容嫣对他爱恨交织。这两个人在他们强大的外表下，隐藏的是两颗满是伤痕的心灵。最后欧阳峰喜欢的女子死在了他家乡的绿洲，黄药师喝了“醉生梦死”后建造了桃花岛，而慕容嫣在日复一日的精神煎熬中变成了独孤求败。这样的结局看罢，留给我的是心中积淀的淡而不逝的莫名沉重的悲哀，也让我不由得思考，是要自由的飞翔，还是要幸福的相爱？影片中欧阳峰后来才明白“看着这天空不断的变化，我才发现，虽然我到这里（沙漠）很久，却从没有看清这沙漠”但是当他明白时，家乡的绿洲，已经成了情人的墓地。昔人已去，美景不再。这一切都是他一手造成的。欧阳峰在很小的时候就认为“要想不被别人拒绝，只有先拒绝别人”正是这样，他拒绝了家乡的绿洲和情人的期待，留给自己的只有那片无言的沙漠。
<br>　　　　 影片中的一幕，鸟笼一刻不停的旋转，将斑驳的光影投射到慕容嫣的脸上，后面是欧阳峰虚化的身影，让我体味到莫名的沉重。也许笼中的三只鸟儿就像他们，不过鸟是被人禁锢的，而他们却是自己禁锢了自己的心灵。洪七是个特例，因为他的单纯、简单。贫女坚持着为弟弟报仇却只能拿出一个鸡蛋，没有人肯帮她，但洪七做到了，虽然他付出了一根指头的代价，他也决不后悔。他觉得找回了自我，最后带着老婆闯荡江湖，这也是影片中的唯一亮色。欧阳峰不是洪七，他虚化的背影之后有的只是逃离、背弃，他只不过是在保护他自己脆弱的自尊。他却不明白在拒绝别人的时候，别人也拒绝了他。也许是沙漠的无情让他如此冷漠，只有当听到情人的死讯后才决定烧了酒店，走出沙漠，回到家乡的绿洲。黄药师在喝了“醉生梦死”之后，忘记了，解脱了，但欧阳峰反而记得更清楚。因为他已经不能再拥有，唯一可做的就是令自己不要忘记。
<br>　　　　 这部关于武侠人物的片段前传、刹那心史，观后让人感觉与都市人生孤独飘零恍惚相通。王家卫的电影看上去随心所欲，骨子里却十分刻意。大量的人物内心独白，多主题的自由言说，以心声为导向，将作品结构成篇，王家卫的电影用他对心灵奥妙的艺术展示对各种人生的生存之道、生命之理做出了他独特的回答。《东邪西毒》中的主人公在过去、现在、未来之间的自由穿梭，曾让人迷惑不懂，但电影是用来看、用来听、用来想，而不是用来懂的。情节再曲折离奇而缺乏思想意义的电影，只能是平庸的剪切组合，让人思索体味而不是为了懂而拍摄的影片才具有独特的电影魅力。王家卫的电影正是因让人体味而精彩。那些忧郁的影调，闪烁不定的光影让人无法拒绝。在我眼中，电影是导演的自由言说，是对人的深层剖析。王家卫电影就是解构心灵的手术刀，从影片人物的自由言话中，我们渐渐的发现了自己。
<br>　　　　 当往事已成灰烬，没有月光宝盒让我们倒退人生，重新拥有；没有“醉生梦死”让我们忘却苦痛，抚平创伤，留下来的只有追悔和希望。追悔是不能再拥有，当你不能够再拥有，你唯一可做的就是令自己不要忘记，希望是为了让我们珍惜今天的拥有，不要在明天追悔。在时间的灰烬中，渐渐的，我找回了自我', '每一个人都是独一无二的，他们各有其不同的困惑难题，也各有其不同的解决方式。作家笔下的人物、电影中的主人公也概莫能外。时间飞逝，若干年后，当我们追寻往事的时候。在时间的灰烬里（Ashs of time）能发掘出什么呢？

